#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005,M=405;
int n,m,a[N],siz,valsiz,mxval;
int k,L[M],R[M],id[N];
int fa[N],rt[M][N];
inline int find(int x)
{
	if(x==fa[x]) return x;
	return fa[x]=find(fa[x]);
}
int cnt[M][N],sumc[M][N],sums[M][M];
int st[N],top;
void update(int p,int l,int r,int x,int y)
{
	int tmp=0,ltmp=L[p],rtmp=R[p],top=0;
	rt[p][x]=rt[p][y]=0;
	for(int i=ltmp;i<=rtmp;++i)
	{
		a[i]=a[find(i)];
		if(a[i]==x||a[i]==y) st[++top]=i;
	}
	for(int i=l;i<=r;++i)
	{
		if(a[i]==x)
		{
			a[i]=y;
			++tmp;
		}
	}
	for(int i=1;i<=top;++i) fa[st[i]]=st[i];
	for(int i=1,t,w;i<=top;++i)
	{
		t=st[i],w=a[t];
		if(!rt[p][w]) rt[p][w]=t;
		else fa[t]=rt[p][w];
	}
	cnt[p][x]-=tmp,cnt[p][y]+=tmp;
	for(int i=p;i<=k;++i)
	{
		sumc[i][x]-=tmp,sumc[i][y]+=tmp;
		if(id[x]!=id[y])
		{
			sums[i][id[x]]-=tmp;
			sums[i][id[y]]+=tmp;
		}
	}
}
int c[N],s[N];//c[val]:临时记录散块中值为val的出现次数       s[bid]:临时记录散块中值落在第bid个值域块的出现次数
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	siz=600,valsiz=317,mxval=1e5;
	k=(n-1)/siz+1;
	for(int i=1;i<=n;++i) cin>>a[i];
	for(int i=1;i<=n;i++) fa[i]=i;
	for(int i=1;i<=mxval;++i) id[i]=(i-1)/valsiz+1;
	for(int i=1;i<=k;++i)
	{
		L[i]=(i-1)*siz+1,R[i]=min(i*siz,n);
		for(int j=L[i];j<=R[i];++j)
		{
			if(!rt[i][a[j]]) rt[i][a[j]]=i;
			else fa[i]=rt[i][a[j]];
			cnt[i][a[j]]++;
		}
		for(int j=1;j<=valsiz;++j)
		{
			sums[i][j]=sums[i-1][j];
		}
		for(int j=1;j<=mxval;++j)
		{
			sumc[i][j]=sumc[i-1][j]+cnt[i][j];
		}
		for(int j=L[i];j<=R[i];++j)
		{
			sums[i][id[a[j]]]++;
		}
	}
	while(m--)
	{
		int op;
		cin>>op;
		int l,r,x,y;
		if(op==1)
		{
			cin>>l>>r>>x>>y;
			if(x==y) continue;
			int lid=(l-1)/siz+1,rid=(r-1)/siz+1;
			if(lid==rid) update(lid,l,r,x,y);
			else
			{
				update(lid,l,R[lid],x,y);
				update(rid,L[rid],r,x,y);
				int tmp,tmpsum=0;//tmp	当前整块 i 中原来值为 x 的元素个数，即本次修改在该块中影响的数量    tmpsum  从 lb+1 到当前块 i 为止，所有整块中 x 的总修改次数
				for(int i=lid+1;i<rid;++i)
				{
					if(rt[i][x])
					{
						if(!rt[i][y])
						{
							rt[i][y]=rt[i][x];
							a[rt[i][x]]=y;
						}
						else fa[rt[i][x]]=rt[i][y];
						rt[i][x]=0;
						tmp=cnt[i][x];
						tmpsum+=tmp;
						cnt[i][y]+=tmp;
						cnt[i][x]=0;
					}
					sumc[i][x]-=tmpsum;
					sumc[i][y]+=tmpsum;
					if(id[x]!=id[y])
					{
						sums[i][id[x]]-=tmpsum;
						sums[i][id[y]]+=tmpsum;
					}
				}
				for(int i=rid;i<=k;++i)
				{
					sumc[i][x]-=tmpsum;
					sumc[i][y]+=tmpsum;
					if(id[x]!=id[y])
					{
						sums[i][id[x]]-=tmpsum;
						sums[i][id[y]]+=tmpsum;
					}
				}
			}
		}
		else
		{
			cin>>l>>r>>x;
			int lid=(l-1)/siz+1,rid=(r-1)/siz+1;
			if(lid==rid)
			{
				for(int i=l;i<=r;++i)
				{
					a[i]=a[find(i)];
					c[a[i]]++;
					s[id[a[i]]]++;
				}
				int vall,valr,tmp=0;
				for(int i=1;i<=valsiz;++i)
				{
					tmp+=s[i];
					if(tmp>=x)
					{
						tmp-=s[i];
						vall=(i-1)*valsiz+1;
						valr=i*valsiz;
						break;
					}
				}
				for(int i=vall;i<=valr;++i)
				{
					tmp+=c[i];
					if(tmp>=x)
					{
						cout<<i<<"\n";
						break;
					}
				}
				for(int i=l;i<=r;++i)
				{
					c[a[i]]--;
					s[id[a[i]]]--;
				}
			}
			else
			{
				for(int i=l;i<=R[lid];++i)
				{
					a[i]=a[find(i)];
					c[a[i]]++;
					s[id[a[i]]]++;
				}
				for(int i=L[rid];i<=r;++i)
				{
					a[i]=a[find(i)];
					c[a[i]]++;
					s[id[a[i]]]++;
				}
				int vall,valr,tmp=0;
				for(int i=1;i<=valsiz;++i)
				{
					tmp+=(s[i]+sums[rid-1][i]-sums[lid][i]);
					if(tmp>=x)
					{
						tmp-=(s[i]+sums[rid-1][i]-sums[lid][i]);
						vall=(i-1)*valsiz+1;
						valr=i*valsiz;
						break;
					}
				}
				for(int i=vall;i<=valr;++i)
				{
					tmp+=(c[i]+sumc[rid-1][i]-sumc[lid][i]);
					if(tmp>=x)
					{
						cout<<i<<"\n";
						break;
					}
				}
				for(int i=l;i<=R[lid];++i)
				{
					c[a[i]]--,s[id[a[i]]]--;
				}
				for(int i=L[rid];i<=r;++i)
				{
					c[a[i]]--,s[id[a[i]]]--;
				}
			}
		}
	}
	return 0;
}
